import React, { useEffect, useState } from "react";
import axios from "axios";

const API_URL = "http://localhost:7000/api/prices";
const CATEGORY_URL = "http://localhost:7000/api/categories";

export default function PriceList() {
  const [items, setItems] = useState([]);
  const [categories, setCategories] = useState([]);
  const [form, setForm] = useState({
    name: "",
    category: "",
    description: "",
    basePrice: "",
    difference: "",
    validTill: "",
    file: null,
  });
  const [editId, setEditId] = useState(null);

  // ===== Fetch prices + categories =====
  useEffect(() => {
    fetchItems();
    fetchCategories();
  }, []);

  const fetchItems = async () => {
    const res = await axios.get(API_URL);
    if (res.data.success) setItems(res.data.data);
  };

  const fetchCategories = async () => {
    const res = await axios.get(CATEGORY_URL);
    if (res.data.success) setCategories(res.data.categories);
  };

  // ===== Handle change =====
  const handleChange = (e) => {
    const { name, value, files } = e.target;
    if (files) setForm({ ...form, file: files[0] });
    else setForm({ ...form, [name]: value });
  };

  // ===== Handle submit =====
  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      const formData = new FormData();
      Object.entries(form).forEach(([key, value]) => {
        if (value) formData.append(key, value);
      });

      if (editId) {
        await axios.put(`${API_URL}/${editId}`, formData);
      } else {
        await axios.post(API_URL, formData);
      }

      setForm({
        name: "",
        category: "",
        description: "",
        basePrice: "",
        difference: "",
        validTill: "",
        file: null,
      });
      setEditId(null);
      fetchItems();
    } catch (err) {
      console.error("❌ Error saving price:", err);
      alert("Error saving price, check console");
    }
  };

  // ===== Handle edit =====
  const handleEdit = (item) => {
    setForm({
      name: item.name,
      category: item.category?._id || "",
      description: item.description || "",
      basePrice: item.basePrice,
      difference: item.difference,
      validTill: item.validTill?.split("T")[0] || "",
      file: null,
    });
    setEditId(item._id);
  };

  // ===== Handle delete =====
  const handleDelete = async (id) => {
    if (window.confirm("Are you sure you want to delete this item?")) {
      await axios.delete(`${API_URL}/${id}`);
      fetchItems();
    }
  };

  return (
    <div className="p-6">
      <h2 className="text-2xl font-bold mb-4 text-center">💰 Price Manager</h2>

      <form onSubmit={handleSubmit} className="bg-gray-100 p-4 rounded mb-6 shadow-md">
        <input
          name="name"
          placeholder="Name"
          value={form.name}
          onChange={handleChange}
          className="border p-2 mb-2 w-full"
        />

        <select
          name="category"
          value={form.category}
          onChange={handleChange}
          className="border p-2 mb-2 w-full"
        >
          <option value="">Select Category</option>
          {categories.map((cat) => (
            <option key={cat._id} value={cat._id}>
              {cat.name}
            </option>
          ))}
        </select>

        <textarea
          name="description"
          placeholder="Description"
          value={form.description}
          onChange={handleChange}
          className="border p-2 mb-2 w-full"
        />

        <input
          type="number"
          name="basePrice"
          placeholder="Base Price"
          value={form.basePrice}
          onChange={handleChange}
          className="border p-2 mb-2 w-full"
        />

        <input
          type="number"
          name="difference"
          placeholder="Difference"
          value={form.difference}
          onChange={handleChange}
          className="border p-2 mb-2 w-full"
        />

        <input
          type="date"
          name="validTill"
          value={form.validTill}
          onChange={handleChange}
          className="border p-2 mb-2 w-full"
        />

        <input type="file" name="file" onChange={handleChange} className="border p-2 mb-3 w-full" />

        <button type="submit" className="bg-blue-600 text-white px-4 py-2 rounded">
          {editId ? "Update" : "Add"}
        </button>
      </form>

      {/* ===== Table ===== */}
      <table className="w-full border-collapse border text-left">
        <thead>
          <tr className="bg-gray-200">
            <th className="border p-2">Name</th>
            <th className="border p-2">Category</th>
            <th className="border p-2">Base Price</th>
            <th className="border p-2">Valid Till</th>
            <th className="border p-2">Image</th>
            <th className="border p-2">Action</th>
          </tr>
        </thead>
        <tbody>
          {items.map((item) => (
            <tr key={item._id}>
              <td className="border p-2">{item.name}</td>
              <td className="border p-2">{item.category?.name || "-"}</td>
              <td className="border p-2">₹{item.basePrice}</td>
              <td className="border p-2">
                {item.validTill ? new Date(item.validTill).toLocaleDateString() : "-"}
              </td>
              <td className="border p-2">
                {item.image ? (
                  <img src={item.image} alt="thumb" className="h-12 w-12 object-cover" />
                ) : (
                  "-"
                )}
              </td>
              <td className="border p-2">
                <button
                  onClick={() => handleEdit(item)}
                  className="bg-yellow-500 text-white px-3 py-1 rounded mr-2"
                >
                  Edit
                </button>
                <button
                  onClick={() => handleDelete(item._id)}
                  className="bg-red-600 text-white px-3 py-1 rounded"
                >
                  Delete
                </button>
              </td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
}
